mapper.select:
SELECT o.*, u.username FROM orders o JOIN users u ON o.user_id = u.id WHERE 1=1
AND (o.order_no LIKE CONCAT('%', #{search}, '%') OR u.username LIKE CONCAT('%', #{search}, '%'))
AND o.status = #{status}
ORDER BY
o.total_amount
o.created_at
o.${sortField}
${sortOrder}
ORDER BY o.created_at DESC
